<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Payments</title><style>body{margin:0;background:#f5f7fb;color:#1f2a37;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif}header{background:#153764;color:white;padding:18px 24px}.wrap{max-width:1180px;margin:0 auto;padding:22px 16px}.card{background:white;border:1px solid #d9dee8;border-radius:8px;padding:18px}.bar{display:grid;grid-template-columns:1.5fr repeat(3,1fr) auto;gap:10px;margin-bottom:14px}input,select{min-height:40px;border:1.5px solid #cbd3df;border-radius:6px;padding:8px 10px}.btn{border:0;border-radius:6px;padding:10px 14px;font-weight:900;text-decoration:none;display:inline-flex;background:#153764;color:white}.btn.light{background:white;color:#153764;border:1.5px solid #d9dee8}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:10px 8px;border-bottom:1px solid #edf0f5;font-size:13px}.status{padding:3px 8px;border-radius:999px;background:#eef3f9;color:#153764;font-weight:900;font-size:11px}.notice{background:#e8f6ef;color:#237a4f;padding:10px 12px;border-radius:8px;margin-bottom:12px}@media(max-width:900px){.bar{grid-template-columns:1fr 1fr}table{display:block;overflow-x:auto}}</style></head><body><header><h1>Payment Records</h1></header><main class="wrap">@if(session('status'))<div class="notice">{{ session('status') }}</div>@endif<div class="card"><form class="bar" method="GET"><input name="search" value="{{ request('search') }}" placeholder="Reference, student, registration"><select name="payment_status"><option value="">Status</option>@foreach(['pending','proof_uploaded','waiting_verification','paid','failed','cancelled','expired','refunded','rejected'] as $status)<option value="{{ $status }}" @selected(request('payment_status')===$status)>{{ $status }}</option>@endforeach</select><select name="payment_method"><option value="">Method</option>@foreach(['manual_bank_transfer','credit_card','atm','cvs','barcode','apple_pay'] as $method)<option value="{{ $method }}" @selected(request('payment_method')===$method)>{{ $method }}</option>@endforeach</select><select name="period"><option value="">Period</option><option value="main">Main</option><option value="late">Late</option></select><button class="btn" type="submit">Filter</button></form><p><a class="btn light" href="{{ route('admin.payments.settings') }}">Payment Settings</a></p><table><thead><tr><th>Reference</th><th>Registration</th><th>Student</th><th>Method</th><th>Status</th><th>Amount</th><th>Updated</th><th></th></tr></thead><tbody>@foreach($payments as $payment)<tr><td>{{ $payment->payment_reference }}</td><td>{{ $payment->registration?->registration_number }}</td><td>{{ $payment->registration?->student_full_name }}</td><td>{{ $payment->payment_method }}</td><td><span class="status">{{ $payment->payment_status }}</span></td><td>{{ $payment->currency }} {{ number_format($payment->grand_total) }}</td><td>{{ $payment->updated_at->format('Y-m-d H:i') }}</td><td><a class="btn light" href="{{ route('admin.payments.show',$payment) }}">View</a></td></tr>@endforeach</tbody></table>{{ $payments->links() }}</div></main></body></html>
